# 1. Read ALL app pages
import os, json

base = "/root/ozmontania-website"
pages = []
for root, dirs, files in os.walk(f"{base}/app"):
    for f in files:
        if f.endswith(".tsx"):
            pages.append(os.path.relpath(os.path.join(root, f), base))

components = os.listdir(f"{base}/components")
content_files = os.listdir(f"{base}/content")
public_dirs = []
if os.path.exists(f"{base}/public/images"):
    for d in os.listdir(f"{base}/public/images"):
        path = f"{base}/public/images/{d}"
        if os.path.isdir(path):
            files = os.listdir(path)
            public_dirs.append(f"{d}/: {files}")

# Read key files
with open(f"{base}/package.json") as f:
    pkg = json.load(f)

deps = {k: pkg.get(k, {}) for k in ["dependencies", "devDependencies"]}

print("=== PAGES (TSX) ===")
for p in sorted(pages):
    print(f"  {p}")

print(f"\n=== COMPONENTS ===")
for c in sorted(components):
    sz = os.path.getsize(f"{base}/components/{c}")
    print(f"  {c} ({sz}B)")

print(f"\n=== CONTENT FILES ===")
for c in sorted(content_files):
    sz = os.path.getsize(f"{base}/content/{c}")
    print(f"  {c} ({sz}B)")

print(f"\n=== PUBLIC/IMAGES ===")
for d in public_dirs:
    print(f"  {d}")

print(f"\n=== DEPENDENCIES ===")
for k, v in deps.items():
    print(f"  {k}: {len(v)} packages")
    for name, ver in sorted(v.items())[:10]:
        print(f"    {name}: {ver}")
"}

